const body = $input.first().json.body ?? $input.first().json;
const data = body.data ?? body;
const key = data.key ?? body.key ?? {};
const message = data.message ?? body.message ?? {};
if (key.fromMe === true) return [];
if ((key.remoteJid ?? '').includes('@g.us')) return [];
const from = (key.remoteJid ?? '')
  .replace('@s.whatsapp.net', '')
  .replace('@g.us', '');
if (!from || from.length < 5) return [];
const texto = (message.conversation ?? message.extendedTextMessage?.text ?? message.buttonsResponseMessage?.selectedDisplayText ?? message.listResponseMessage?.singleSelectReply?.selectedRowId ?? '').trim();
const buttonId = message.buttonsResponseMessage?.selectedButtonId ?? message.listResponseMessage?.singleSelectReply?.selectedRowId ?? null;
return [{ json: { from, texto, buttonId } }];

const p = $('Parsear Mensagem').item.json;
let clientes = [], sessoes = [];
try { const t = $('GET Cliente').item.json.data ?? $('GET Cliente').item.json; clientes = typeof t === 'string' ? JSON.parse(t) : (Array.isArray(t) ? t : []); } catch (e) { clientes = []; }
try { const t = $('GET Sessao').item.json.data ?? $('GET Sessao').item.json; sessoes = typeof t === 'string' ? JSON.parse(t) : (Array.isArray(t) ? t : []); } catch (e) { sessoes = []; }
const cliente = clientes[0] ?? null;
const sessao = sessoes[0] ?? null;
return [{ json: {
  from: p.from,
  texto: p.texto,
  buttonId: p.buttonId,
  clienteExiste: cliente !== null,
  clienteId: cliente?.id ?? null,
  clienteNome: cliente?.nome ?? null,
  clientePet: cliente?.pet_nome ?? null,
  clientePetTipo: cliente?.pet_tipo ?? null,
  sessaoEtapa: sessao?.etapa ?? null,
  sessaoDados: sessao?.dados ?? {}
} }];

const d = $json;
const texto = (d.texto ?? '').trim();
const etapa = d.sessaoEtapa;
const dados = d.sessaoDados ?? {};
const upper = texto.toUpperCase();
let prox = null;
let resp = '';

if (upper === 'CANCELAR') {
  resp = '✅ Tudo bem! Se quiser, volte a qualquer momento digitando MENU.';
  return [{ json: { from: d.from, resp, prox: null, saveSession: false } }];
}

if (!d.clienteExiste) {
  if (!etapa) {
    resp = 'Olá! Bem-vindo ao Pet Shop Zap 😊

Primeiro me diga o seu nome e o nome do seu pet:';
    prox = 'aguardando_cadastro';
  } else if (etapa === 'aguardando_cadastro') {
    const parts = texto.split(/\||-/).map(p => p.trim()).filter(Boolean);
    if (parts.length < 2) {
      resp = '⚠️ Por favor, envie no formato: seu nome | nome do pet';
      prox = 'aguardando_cadastro';
    } else {
      resp = `Obrigado, *${parts[0]}*! Seu pet *${parts[1]}* já está registrado.

Digite MENU para ver o menu do Pet Zap.`;
      prox = null;
      return [{ json: { from: d.from, resp, prox, saveSession: false, createCustomer: true, customerData: { nome: parts[0], pet_nome: parts[1] } } }];
    }
  }
  return [{ json: { from: d.from, resp, prox, saveSession: true, createCustomer: false, customerData: null } }];
}

if (upper === 'MENU' || texto === '0') {
  resp = `👋 Olá ${d.clienteNome}! Aqui está o menu do Pet Zap:

1️⃣ Ver produtos
2️⃣ Reservar tosa
3️⃣ Reservar banho
4️⃣ Meus pedidos
5️⃣ Falar com atendimento`;
  return [{ json: { from: d.from, resp, prox: null, saveSession: false } }];
}

if (!etapa) {
  resp = `Olá ${d.clienteNome}! Escolha uma opção:

1️⃣ Ver produtos
2️⃣ Reservar tosa
3️⃣ Reservar banho
4️⃣ Meus pedidos
5️⃣ Falar com atendimento`;
  return [{ json: { from: d.from, resp, prox: null, saveSession: false } }];
}

if (etapa === 'reserva_tosa') {
  resp = 'Perfeito! Envie a data e horário da tosa no formato DD/MM/YYYY hh:mm';
  return [{ json: { from: d.from, resp, prox: 'reserva_tosa_data', saveSession: true } }];
}

if (etapa === 'reserva_tosa_data') {
  resp = `Reserva de tosa agendada para *${texto}*. Obrigado!`;
  return [{ json: { from: d.from, resp, prox: null, saveSession: false, createBooking: true, bookingData: { tipo_servico: 'tosa', horario: texto } } }];
}

if (etapa === 'reserva_banho') {
  resp = 'Perfeito! Envie a data e horário do banho no formato DD/MM/YYYY hh:mm';
  return [{ json: { from: d.from, resp, prox: 'reserva_banho_data', saveSession: true } }];
}

if (etapa === 'reserva_banho_data') {
  resp = `Reserva de banho agendada para *${texto}*. Obrigado!`;
  return [{ json: { from: d.from, resp, prox: null, saveSession: false, createBooking: true, bookingData: { tipo_servico: 'banho', horario: texto } } }];
}

if (texto === '1') {
  resp = 'Aqui estão nossos produtos em destaque:

- Ração Premium 2kg
- Shampoos Naturais
- Petiscos Saudáveis

Envie o nome do produto para ver detalhes ou fazer pedido.';
  return [{ json: { from: d.from, resp, prox: null, saveSession: false } }];
}

if (texto === '2') {
  resp = 'Ótimo! Vamos agendar sua tosa. Envie a data e horário no formato DD/MM/YYYY hh:mm.';
  return [{ json: { from: d.from, resp, prox: 'reserva_tosa', saveSession: true } }];
}

if (texto === '3') {
  resp = 'Ótimo! Vamos agendar o banho. Envie a data e horário no formato DD/MM/YYYY hh:mm.';
  return [{ json: { from: d.from, resp, prox: 'reserva_banho', saveSession: true } }];
}

if (texto === '4') {
  resp = 'Buscando seus pedidos... Em breve você receberá a lista de seus pedidos ativos.';
  return [{ json: { from: d.from, resp, prox: null, saveSession: false } }];
}

resp = 'Não entendi. Digite MENU para ver as opções novamente.';
return [{ json: { from: d.from, resp, prox: null, saveSession: false } }];
